def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 1.5:
            priorities[i] = 1000 + (ratio - 1) * 150
        elif ratio == 1.5:
            priorities[i] = 200
        elif ratio > 1:
            priorities[i] = 150 + (1.5 - ratio) * 100
        else:
            score1 = 0
            score2 = 0
            for j in range(1, 7):
                temp = ((capacity - item) / capacity) ** j
                if temp < 0.05:
                    score1 += temp * 60 / j
                elif temp < 0.2:
                    score1 += temp * 20
                else:
                    score1 += temp * 5 / (j*j)
            for k in range(1, 4):
                temp2 = np.sin((capacity - item) * k) * np.exp(-item / capacity * k)
                if temp2 > 0:
                    score2 += temp2 * 10 * k
                else:
                    score2 += abs(temp2) * 2 / k
            total_score = score1 - score2
            if total_score <= 0:
                priorities[i] = 1e6
            elif total_score < 0.05:
                priorities[i] = total_score * 100
            elif total_score < 1:
                priorities[i] = 1 / total_score
            else:
                adjusted = (total_score - 1) * 0.5 + 1
                priorities[i] = 1 / adjusted
    return priorities
